      ('sensory_contract', '{"profile":"creamy_delicate","scores":{"sweet":1,"salty":3,"acidic":1,"bitter":0,"umami":4,"heat":0,"pungency":1,"richness":4,"freshness":2,"intensity":3},"dominant_flavors":["crémeux","doux","savoureux"],"aroma_families":["ail","oignon_compoté","champignon_terreux","beurre","lacté","agrume"],"target_textures":["tendre","contraste_léger"],"signature_ingredients":["Épaule de veau crue, en cubes","Carotte crue","Poireau cru","Oignon jaune cru"],"identity_guardrails":["conserver_les_ingrédients_signatures","conserver_la_technique_centrale","ne_pas_remplacer_par_un_simple_équivalent_nutritionnel"]}'::jsonb, 'myko_v3_sensory_contract')
  ) AS provenance(field_name, field_value, transformation_rule) ON true
  JOIN LATERAL (
    SELECT id FROM ops.import_runs WHERE configuration_hash = 'e866aa233ad9fcc4ff838f853594e96d' LIMIT 1
  ) run ON true
  WHERE ds.code = 'myko_editorial_v3';
