  SET planning_eligible = v_static_eligible AND v_missing = 0,
      eligibility_issues = CASE WHEN v_missing = 0
        THEN '[]'::jsonb
        ELSE jsonb_build_array(jsonb_build_object('code', 'unresolved_required_forms', 'count', v_missing))
      END
  WHERE id = v_version;

  IF v_missing > 0 THEN
