    (entity_type, entity_id, task_type, priority, reason_codes, proposed_changes, status)
  VALUES
    ('recipe_version', v_version, 'variants_need_branch_modeling', 5,
     ARRAY['variants_not_modeled'], '{"recipe_code":"FR-003","variants":["Pain de campagne + moutarde si pain d’épices absent","bière ambrée moins sucrée"]}'::jsonb, 'open');

