    ARRAY['lacté','fumé']::text[], ARRAY['dessus_doré','intérieur_fondant_ou_crémeux']::text[],
    ARRAY['Pâte brisée crue','Lardon fumé cru','Œuf cru','Crème fraîche liquide entière']::text[], ARRAY['conserver_les_ingrédients_signatures','conserver_la_technique_centrale','ne_pas_remplacer_par_un_simple_équivalent_nutritionnel']::text[],
    ARRAY['fonçage','précuisson de garniture','appareil à crème prise','cuisson au four']::text[], ARRAY['Version canonique sans fromage','oignon ou emmental seulement comme variantes non traditionnelles']::text[], ARRAY['gluten','lait','œuf']::text[],
    '3 jours au réfrigérateur.', false, '[]'::jsonb
  FROM ops.source_datasets ds WHERE ds.code = 'myko_editorial_v3'
  ON CONFLICT (recipe_family_id, version_number) DO UPDATE SET
    title = EXCLUDED.title,
    source_dataset_id = EXCLUDED.source_dataset_id,
    source_record_key = EXCLUDED.source_record_key,
    servings = EXCLUDED.servings,
    prep_minutes = EXCLUDED.prep_minutes,
    cook_minutes = EXCLUDED.cook_minutes,
    difficulty = EXCLUDED.difficulty,
    quality_level = EXCLUDED.quality_level,
    publication_status = 'candidate',
    content_hash = EXCLUDED.content_hash,
    sensory_scores = EXCLUDED.sensory_scores,
    dominant_flavors = EXCLUDED.dominant_flavors,
    aroma_families = EXCLUDED.aroma_families,
    target_textures = EXCLUDED.target_textures,
    signature_ingredients = EXCLUDED.signature_ingredients,
    identity_guardrails = EXCLUDED.identity_guardrails,
    techniques = EXCLUDED.techniques,
    variant_candidates = EXCLUDED.variant_candidates,
    allergens = EXCLUDED.allergens,
    conservation_text = EXCLUDED.conservation_text,
    planning_eligible = false,
    eligibility_issues = '[]'::jsonb
  RETURNING id INTO v_version;

