  VALUES
    ('Poulet rôti et pommes de terre', 'poulet roti et pommes de terre', 'France / cuisine domestique internationale', 'France / cuisine domestique internationale',
     'meal', 'rôti', 'domestic_standard', 'warm_aromatic',
     'candidate', 'B')
  ON CONFLICT (canonical_name_normalized) DO UPDATE SET
    canonical_name = EXCLUDED.canonical_name,
    culinary_origin = EXCLUDED.culinary_origin,
    cuisine_origin = EXCLUDED.cuisine_origin,
    dish_structure = EXCLUDED.dish_structure,
