       jsonb_build_object('recipe_code', 'REAL-132', 'missing_required_count', v_missing), 'open');
  END IF;

  DELETE FROM ops.field_provenance
  WHERE entity_schema = 'culinary' AND entity_table = 'recipe_versions'
