      WHERE ff.canonical_name_normalized = 'levure chimique' AND ff.status <> 'rejected'
      ORDER BY CASE ff.status WHEN 'published' THEN 0 ELSE 1 END, ff.confidence_level
      LIMIT 1),
     8, 'g', 'required',
     'aération', false, 4);

